package com.deliveryworkbench.entity;

import jakarta.persistence.*;
import lombok.*;

import java.time.OffsetDateTime;

/**
 * QA test scenario tied to a delivery request.
 * Can be created by a human QA engineer or generated by MockAIService as a draft.
 * AI-generated scenarios must be reviewed and approved by QA before use (BR-04, BR-05).
 */
@Entity
@Table(name = "qa_test_scenarios",
    indexes = {
        @Index(name = "idx_qa_request_id", columnList = "request_id"),
        @Index(name = "idx_qa_status", columnList = "status")
    })
@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
@Builder
public class QATestScenario {

    @Id
    @GeneratedValue(strategy = GenerationType.SEQUENCE, generator = "qa_test_scenarios_seq")
    @SequenceGenerator(name = "qa_test_scenarios_seq", sequenceName = "qa_test_scenarios_seq", allocationSize = 1)
    private Long id;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "request_id", nullable = false)
    private DeliveryRequest request;

    @Column(name = "scenario_name", nullable = false, length = 255)
    private String scenarioName;

    @Enumerated(EnumType.STRING)
    @Column(name = "scenario_type", nullable = false, length = 20)
    @Builder.Default
    private ScenarioType scenarioType = ScenarioType.POSITIVE;

    @Column(columnDefinition = "TEXT")
    private String precondition;

    @Column(name = "test_steps", columnDefinition = "TEXT")
    private String testSteps;

    @Column(name = "expected_result", columnDefinition = "TEXT")
    private String expectedResult;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false, length = 15)
    @Builder.Default
    private ScenarioStatus status = ScenarioStatus.DRAFT;

    /** Username of the person who created this scenario (or "AI"). */
    @Column(name = "created_by", length = 100)
    private String createdBy;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false, length = 10)
    @Builder.Default
    private QuestionSource source = QuestionSource.HUMAN;

    @Column(name = "created_at", nullable = false, updatable = false)
    private OffsetDateTime createdAt;

    @PrePersist
    protected void onCreate() {
        createdAt = OffsetDateTime.now();
    }
}
